import anthropic, time

client = anthropic.Anthropic()

def resilient_call(messages, model="claude-opus-4-8", max_retries=4):
    """Exponential backoff retry for transient API errors."""
    delay = 1.0
    for attempt in range(max_retries):
        try:
            return client.messages.create(
                model=model,
                max_tokens=1024,
                messages=messages,
            )
        except (anthropic.APIConnectionError, anthropic.RateLimitError,
                anthropic.InternalServerError) as e:
            if attempt == max_retries - 1:
                raise
            print(f"Attempt {attempt + 1} failed: {e}. Retrying in {delay}s")
            time.sleep(delay)
            delay = min(delay * 2, 30)

import anthropic
import os

# Each region gets its own client
clients = {
    "us": anthropic.Anthropic(api_key=os.environ["ANTHROPIC_API_KEY"]),
    # For Bedrock, swap to boto3 clients per region
}

SYSTEM_PROMPT = """You are a helpful assistant for Acme Corp...
[insert your 10,000-token static context here]
"""

def call_with_cache(messages: list, region: str = "us"):
    client = clients[region]
    return client.messages.create(
        model="claude-opus-4-8",
        max_tokens=1024,
        system=[
            {
                "type": "text",
                "text": SYSTEM_PROMPT,
                "cache_control": {"type": "ephemeral"},  # cache in this region
            }
        ],
        messages=messages,
    )

import boto3, json, time

PRIMARY_REGION = "us-east-1"
FALLBACK_REGION = "us-west-2"

def call_with_regional_fallback(body: dict) -> dict:
    for region in [PRIMARY_REGION, FALLBACK_REGION]:
        bedrock = boto3.client("bedrock-runtime", region_name=region)
        try:
            response = bedrock.invoke_model(
                modelId="anthropic.claude-opus-4-8",
                body=json.dumps(body),
            )
            return json.loads(response["body"].read())
        except bedrock.exceptions.ThrottlingException:
            if region == FALLBACK_REGION:
                raise
            time.sleep(0.5)   # brief pause before failover
        except bedrock.exceptions.ServiceUnavailableException:
            if region == FALLBACK_REGION:
                raise
    raise RuntimeError("Both regions unavailable")
